import { Component, OnInit } from '@angular/core';
import { VehiclesService } from '../../services/vehicles.service';
import { Vehicle } from '../../core/data.models';
import { Observable } from 'rxjs';

@Component({
  selector: 'app-vehicles-list',
  templateUrl: './vehicles-list.component.html'
})
export class VehiclesListComponent implements OnInit {
  vehicles$: Observable<Vehicle[]>;

  constructor(private svc: VehiclesService) {
    this.vehicles$ = this.svc.list$;
  }

  ngOnInit(): void {}

  remove(id: string) {
    this.svc.remove(id);
  }
}
<div class="header vehicles-header">
  <h2>Vehicles</h2>
  <button class="btn" routerLink="new">Add</button>
</div>

<div class="grid">
  <ng-container *ngIf="vehicles$ | async as list">
    <div *ngIf="list.length === 0" class="card">No vehicles. Click Add to create one.</div>
    <div *ngFor="let v of list" class="card">
      <h3>{{v.make}} {{v.model}}</h3>
      <div class="small">Year: {{v.year || '—'}} | Mileage: {{v.mileage || '—'}} km</div>
      <div style="margin-top:8px">
        <a [routerLink]="[v.id]">View</a>
        <a [routerLink]="[v.id, 'edit']" style="margin-left:8px">Edit</a>
        <button style="margin-left:8px" (click)="remove(v.id)">Delete</button>
      </div>
    </div>
  </ng-container>
</div>
